#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
long long dp[2001][2001];
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    dp[0][0] = 1;
    for (int i = 1; i <= N; i++) {
        for (int j = 1; j <= M; j++) {
            dp[i][j] = (dp[i - 1][j - 1] + dp[i - 1][j] * (j - 1)) % MOD;
        }
    }
    printf("%lld\n", dp[N][M]);
    return 0;
}

